import { useState, useEffect } from "react";
import axios from "axios";

const API = "http://127.0.0.1:5000";

export default function App() {
  const [email, setEmail] = useState("");
  const [apiKey, setApiKey] = useState("");
  const [usage, setUsage] = useState([]);
  const [filteredUsage, setFilteredUsage] = useState([]);
  const [response, setResponse] = useState("");
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState("");
  const [query, setQuery] = useState("");
  const [dark, setDark] = useState(true);

  const theme = dark
    ? {
        bg: "#0f172a",
        card: "#1e293b",
        text: "#e2e8f0",
        accent: "#8b5cf6",
        border: "#334155",
      }
    : {
        bg: "#f8fafc",
        card: "#ffffff",
        text: "#020617",
        accent: "#6366f1",
        border: "#e2e8f0",
      };

  useEffect(() => {
    setFilteredUsage(
      usage.filter((u) =>
        u.url.toLowerCase().includes(query.toLowerCase())
      )
    );
  }, [query, usage]);

  const signup = async () => {
    try {
      setLoading(true);
      const res = await axios.post(`${API}/auth/signup`, { email });
      setApiKey(res.data.apiKey);
      setMessage("API Key generated");
    } catch {
      setMessage("Something went wrong");
    } finally {
      setLoading(false);
    }
  };

  const callAPI = async () => {
    try {
      setLoading(true);
      const res = await axios.get(
        `${API}/proxy?url=https://jsonplaceholder.typicode.com/todos/1&apiKey=${apiKey}`
      );
      setResponse(JSON.stringify(res.data, null, 2));
    } catch {
      setMessage("API failed");
    } finally {
      setLoading(false);
    }
  };

  const fetchUsage = async () => {
    const res = await axios.get(`${API}/usage/${apiKey}`);
    setUsage(res.data);
  };

  const billing = (usage.length * 0.2).toFixed(2);

  return (
    <div style={{ background: theme.bg, minHeight: "100vh", color: theme.text, fontFamily: "Segoe UI" }}>

      {/* NAVBAR */}
      <div style={styles.navbar(theme)}>
        <h2>MeterFlow</h2>

        <div style={styles.navItems}>
          <span>Dashboard</span>
          <span>Usage</span>
          <span>Billing</span>
        </div>

        {/* 🌙 / ☀️ THEME TOGGLE */}
        <button style={styles.toggleBtn(theme)} onClick={() => setDark(!dark)}>
          {dark ? "☀️" : "🌙"}
        </button>
      </div>

      <div style={styles.main}>

        <h1 style={{ marginBottom: "10px" }}>Dashboard</h1>
        {message && <p style={{ color: theme.accent }}>{message}</p>}

        {/* CARDS */}
        <div style={styles.cards}>
          <Card title="Requests" value={usage.length} theme={theme} />
          <Card title="Billing" value={`₹${billing}`} theme={theme} />
          <Card title="Status" value={apiKey ? "Active" : "Inactive"} theme={theme} />
        </div>

        {/* API KEY */}
        <div style={styles.card(theme)}>
          <input
            placeholder="Enter email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            style={styles.input}
          />
          <button style={styles.primaryBtn(theme)} onClick={signup}>
            {loading ? "..." : "Generate Key"}
          </button>

          {apiKey && <p style={{ marginTop: "10px", fontSize: "12px" }}>{apiKey}</p>}
        </div>

        {/* PLAYGROUND */}
        {apiKey && (
          <div style={styles.card(theme)}>
            <button style={styles.primaryBtn(theme)} onClick={callAPI}>
              Call API
            </button>

            <button style={styles.secondaryBtn(theme)} onClick={fetchUsage}>
              Load Usage
            </button>

            {response && <pre style={styles.pre}>{response}</pre>}
          </div>
        )}

        {/* SEARCH */}
        <input
          placeholder="Search logs..."
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          style={styles.input}
        />

        {/* TABLE */}
        <div style={styles.card(theme)}>
          <table style={styles.table}>
            <thead>
              <tr>
                <th>URL</th>
                <th>Status</th>
                <th>Time</th>
              </tr>
            </thead>
            <tbody>
              {filteredUsage.map((u, i) => (
                <tr key={i}>
                  <td>{u.url}</td>
                  <td>{u.status}</td>
                  <td>{new Date(u.timestamp).toLocaleString()}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

      </div>
    </div>
  );
}

function Card({ title, value, theme }) {
  return (
    <div style={styles.card(theme)}>
      <h4>{title}</h4>
      <h2>{value}</h2>
    </div>
  );
}

const styles = {
  navbar: (theme) => ({
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: "15px 30px",
    borderBottom: `1px solid ${theme.border}`,
  }),

  navItems: {
    display: "flex",
    gap: "20px",
  },

  toggleBtn: (theme) => ({
    background: theme.card,
    border: "none",
    padding: "8px 12px",
    borderRadius: "8px",
    cursor: "pointer",
  }),

  main: {
    padding: "30px",
  },

  cards: {
    display: "flex",
    gap: "15px",
    marginBottom: "20px",
  },

  card: (theme) => ({
    flex: 1,
    background: theme.card,
    padding: "20px",
    borderRadius: "12px",
    boxShadow: "0 6px 20px rgba(0,0,0,0.2)",
    marginBottom: "20px",
  }),

  input: {
    padding: "10px",
    marginRight: "10px",
    borderRadius: "8px",
    border: "1px solid #ccc",
  },

  primaryBtn: (theme) => ({
    background: theme.accent,
    color: "white",
    padding: "10px 15px",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer",
    marginRight: "10px",
  }),

  secondaryBtn: (theme) => ({
    background: "transparent",
    border: `1px solid ${theme.accent}`,
    color: theme.accent,
    padding: "10px 15px",
    borderRadius: "8px",
    cursor: "pointer",
  }),

  pre: {
    background: "#020617",
    color: "#22c55e",
    padding: "10px",
    marginTop: "10px",
    borderRadius: "8px",
  },

  table: {
    width: "100%",
    marginTop: "10px",
  },
};
